import{_ as e,o as l,c as d,ag as a}from"./chunks/framework.DTiDeF2Q.js";const x=JSON.parse('{"title":"Gitエイリアス | Dotfiles (JA)","titleTemplate":":title","description":"Gitシェルエイリアス。コミット、ブランチ、差分、リモート操作を高速化する80以上のショートカット。","frontmatter":{"title":"Gitエイリアス | Dotfiles","description":"Gitシェルエイリアス。コミット、ブランチ、差分、リモート操作を高速化する80以上のショートカット。","lang":"ja-JP","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Gitエイリアス preview","canonical":"/ja/aliases/git/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Gitエイリアス","pageType":"docs","schemaType":"WebPage","metaTitle":"Gitエイリアス - Dotfiles (JP)","permalink":"/ja/aliases/git/","sidebar":true,"meta":[{"name":"keywords","content":"git aliases, git shortcuts, git dotfiles, git commit, git branch, shell, bash, zsh"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Gitシェルエイリアス。コミット、ブランチ、差分、リモート操作を高速化する80以上のショートカット。"},{"name":"twitter:title","content":"Gitエイリアス - Dotfiles"},{"name":"og:title","content":"Gitエイリアス - Dotfiles"},{"name":"og:description","content":"Gitシェルエイリアス。コミット、ブランチ、差分、リモート操作を高速化する80以上のショートカット。"},{"name":"og:image:alt","content":"Dotfiles - シェルライフにフィットするシンプルな設計"},{"name":"og:locale","content":"ja_JP"}]},"headers":[],"relativePath":"ja/aliases/git/index.md","filePath":"ja/aliases/git/index.md","lastUpdated":1773010926000}'),i={name:"ja/aliases/git/index.md"};function o(g,t,s,c,n,r){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="gitエイリアス" tabindex="-1">Gitエイリアス <a class="header-anchor" href="#gitエイリアス" aria-label="Permalink to &quot;Gitエイリアス&quot;">​</a></h1><p>バージョン管理ワークフローを強力なショートカットで効率化。</p><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p>Gitエイリアスは頻繁に使用するGitコマンドのショートカットを作成します。<a href="https://github.com/sebastienrousseau/dotfiles" target="_blank" rel="noreferrer">Dotfiles</a>設定の一部で、Chezmoiによって自動的にロードされます。</p><p><code>git.aliases.sh</code>と<code>signing.aliases.sh</code>で定義され、インストール後は任意のBashまたはZshセッションで利用できます。</p><h2 id="リファレンス" tabindex="-1">リファレンス <a class="header-anchor" href="#リファレンス" aria-label="Permalink to &quot;リファレンス&quot;">​</a></h2><h3 id="コア" tabindex="-1">コア <a class="header-anchor" href="#コア" aria-label="Permalink to &quot;コア&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>g</code></td><td style="text-align:left;"><code>git</code></td><td style="text-align:left;">gitの省略形</td></tr><tr><td style="text-align:left;"><code>gtp</code></td><td style="text-align:left;"><code>git rev-parse --show-toplevel</code></td><td style="text-align:left;">リポジトリのトップレベルディレクトリを表示</td></tr><tr><td style="text-align:left;"><code>grpa</code></td><td style="text-align:left;"><code>git rev-parse --abbrev-ref HEAD</code></td><td style="text-align:left;">現在のブランチ名を表示</td></tr><tr><td style="text-align:left;"><code>gconfl</code></td><td style="text-align:left;"><code>git config --list</code></td><td style="text-align:left;">すべてのGit設定を一覧表示</td></tr><tr><td style="text-align:left;"><code>gconfr</code></td><td style="text-align:left;"><code>git config --local --get remote.origin.url</code></td><td style="text-align:left;">リモートorigin URLを表示</td></tr><tr><td style="text-align:left;"><code>gconfdiff</code></td><td style="text-align:left;"><code>git config alias.dcolor &quot;diff --color-words&quot;</code></td><td style="text-align:left;">カラー差分エイリアスを設定</td></tr></tbody></table><h3 id="作業エリア" tabindex="-1">作業エリア <a class="header-anchor" href="#作業エリア" aria-label="Permalink to &quot;作業エリア&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ga</code></td><td style="text-align:left;"><code>git add</code></td><td style="text-align:left;">ファイルをステージング</td></tr><tr><td style="text-align:left;"><code>gaa</code></td><td style="text-align:left;"><code>git add --all</code></td><td style="text-align:left;">すべての変更をステージング</td></tr><tr><td style="text-align:left;"><code>gad</code></td><td style="text-align:left;"><code>git add .</code></td><td style="text-align:left;">カレントディレクトリをステージング</td></tr><tr><td style="text-align:left;"><code>gau</code></td><td style="text-align:left;"><code>git add --update</code></td><td style="text-align:left;">変更と削除をステージング</td></tr><tr><td style="text-align:left;"><code>gcl</code></td><td style="text-align:left;"><code>git clone</code></td><td style="text-align:left;">リポジトリをクローン</td></tr><tr><td style="text-align:left;"><code>gin</code></td><td style="text-align:left;"><code>git init</code></td><td style="text-align:left;">新しいGitリポジトリを初期化</td></tr><tr><td style="text-align:left;"><code>gco</code></td><td style="text-align:left;"><code>git checkout</code></td><td style="text-align:left;">ブランチを切り替え</td></tr><tr><td style="text-align:left;"><code>gcb</code></td><td style="text-align:left;"><code>git checkout -b</code></td><td style="text-align:left;">新しいブランチを作成して切り替え</td></tr><tr><td style="text-align:left;"><code>gdis</code></td><td style="text-align:left;"><code>git checkout --</code></td><td style="text-align:left;">作業ディレクトリの変更を破棄</td></tr><tr><td style="text-align:left;"><code>grs</code></td><td style="text-align:left;"><code>git restore</code></td><td style="text-align:left;">作業ツリーファイルを復元</td></tr><tr><td style="text-align:left;"><code>gmv</code></td><td style="text-align:left;"><code>git mv</code></td><td style="text-align:left;">ファイルを移動または名前変更</td></tr><tr><td style="text-align:left;"><code>grm</code></td><td style="text-align:left;"><code>git rm</code></td><td style="text-align:left;">ファイルを削除</td></tr><tr><td style="text-align:left;"><code>grmc</code></td><td style="text-align:left;"><code>git rm --cached</code></td><td style="text-align:left;">ファイルをアンステージング</td></tr><tr><td style="text-align:left;"><code>gst</code></td><td style="text-align:left;"><code>git status</code></td><td style="text-align:left;">作業ツリーの状態を表示</td></tr><tr><td style="text-align:left;"><code>gsts</code></td><td style="text-align:left;"><code>git status --short</code></td><td style="text-align:left;">短形式で状態を表示</td></tr><tr><td style="text-align:left;"><code>gstsb</code></td><td style="text-align:left;"><code>git status --short --branch</code></td><td style="text-align:left;">ブランチ情報付きの短形式状態</td></tr><tr><td style="text-align:left;"><code>gsta</code></td><td style="text-align:left;"><code>git stash save</code></td><td style="text-align:left;">現在の変更をスタッシュ</td></tr><tr><td style="text-align:left;"><code>gstp</code></td><td style="text-align:left;"><code>git stash pop</code></td><td style="text-align:left;">最新のスタッシュを適用</td></tr><tr><td style="text-align:left;"><code>gstd</code></td><td style="text-align:left;"><code>git stash drop</code></td><td style="text-align:left;">最新のスタッシュを削除</td></tr><tr><td style="text-align:left;"><code>gclout</code></td><td style="text-align:left;"><code>git clean -df &amp;&amp; git checkout -- .</code></td><td style="text-align:left;">すべての変更を破棄</td></tr></tbody></table><h3 id="コミット" tabindex="-1">コミット <a class="header-anchor" href="#コミット" aria-label="Permalink to &quot;コミット&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gc</code></td><td style="text-align:left;"><code>git commit -a</code></td><td style="text-align:left;">追跡済みの変更をコミット</td></tr><tr><td style="text-align:left;"><code>gca</code></td><td style="text-align:left;"><code>git commit --amend</code></td><td style="text-align:left;">最後のコミットを修正</td></tr><tr><td style="text-align:left;"><code>gcall</code></td><td style="text-align:left;"><code>git add -A &amp;&amp; git commit -av</code></td><td style="text-align:left;">すべてをステージングしてコミット</td></tr><tr><td style="text-align:left;"><code>gcam</code></td><td style="text-align:left;"><code>git commit --amend --message</code></td><td style="text-align:left;">新しいメッセージでコミットを修正</td></tr><tr><td style="text-align:left;"><code>gcane</code></td><td style="text-align:left;"><code>git commit --amend --no-edit</code></td><td style="text-align:left;">メッセージを変更せずに修正</td></tr><tr><td style="text-align:left;"><code>gcm</code></td><td style="text-align:left;"><code>git commit --message</code></td><td style="text-align:left;">インラインメッセージでコミット</td></tr></tbody></table><h3 id="差分と履歴" tabindex="-1">差分と履歴 <a class="header-anchor" href="#差分と履歴" aria-label="Permalink to &quot;差分と履歴&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gd</code></td><td style="text-align:left;"><code>git diff</code></td><td style="text-align:left;">ステージングされていない変更を表示</td></tr><tr><td style="text-align:left;"><code>gdch</code></td><td style="text-align:left;"><code>git diff --name-status</code></td><td style="text-align:left;">変更されたファイルの名前を表示</td></tr><tr><td style="text-align:left;"><code>gdh</code></td><td style="text-align:left;"><code>git diff HEAD</code></td><td style="text-align:left;">最後のコミット以降の変更を表示</td></tr><tr><td style="text-align:left;"><code>gdstaged</code></td><td style="text-align:left;"><code>git diff --staged</code></td><td style="text-align:left;">ステージングされた変更を表示</td></tr><tr><td style="text-align:left;"><code>gdcached</code></td><td style="text-align:left;"><code>git diff --cached</code></td><td style="text-align:left;">インデックスとHEAD間の変更を表示</td></tr><tr><td style="text-align:left;"><code>gdstat</code></td><td style="text-align:left;"><code>git diff --stat --ignore-space-change -r</code></td><td style="text-align:left;">diffstatを生成</td></tr><tr><td style="text-align:left;"><code>gl</code></td><td style="text-align:left;"><code>git log --since=&quot;last month&quot; --oneline</code></td><td style="text-align:left;">過去1ヶ月の1行ログ</td></tr><tr><td style="text-align:left;"><code>glg</code></td><td style="text-align:left;"><code>git log --graph --all --oneline --decorate</code></td><td style="text-align:left;">全ブランチのグラフログ</td></tr><tr><td style="text-align:left;"><code>glgg</code></td><td style="text-align:left;"><code>git log --oneline --graph --full-history --all --color --decorate</code></td><td style="text-align:left;">完全履歴グラフログ</td></tr><tr><td style="text-align:left;"><code>glc</code></td><td style="text-align:left;"><code>git log --oneline --reverse</code></td><td style="text-align:left;">時系列の1行ログ</td></tr><tr><td style="text-align:left;"><code>gld</code></td><td style="text-align:left;"><code>git log --since=1-day-ago</code></td><td style="text-align:left;">過去24時間のログ</td></tr><tr><td style="text-align:left;"><code>gldc</code></td><td style="text-align:left;"><code>git log -1 --date-order --format=%cI</code></td><td style="text-align:left;">最新コミットのISO 8601日付</td></tr><tr><td style="text-align:left;"><code>gldl</code></td><td style="text-align:left;"><code>git log --date=local</code></td><td style="text-align:left;">ローカルタイムゾーンでのログ</td></tr><tr><td style="text-align:left;"><code>glf</code></td><td style="text-align:left;"><code>git log ORIG_HEAD.. --stat --no-merges</code></td><td style="text-align:left;">フェッチ後の新しいコミット</td></tr><tr><td style="text-align:left;"><code>gll</code></td><td style="text-align:left;"><em>(装飾グラフ形式)</em></td><td style="text-align:left;">詳細グラフログ</td></tr></tbody></table><h3 id="ブランチ" tabindex="-1">ブランチ <a class="header-anchor" href="#ブランチ" aria-label="Permalink to &quot;ブランチ&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gb</code></td><td style="text-align:left;"><code>git branch</code></td><td style="text-align:left;">ローカルブランチを一覧表示</td></tr><tr><td style="text-align:left;"><code>gbd</code></td><td style="text-align:left;"><code>git branch -d</code></td><td style="text-align:left;">マージ済みブランチを削除</td></tr><tr><td style="text-align:left;"><code>gbl</code></td><td style="text-align:left;"><code>git branch -l</code></td><td style="text-align:left;">パターンにマッチするブランチを一覧表示</td></tr><tr><td style="text-align:left;"><code>gbr</code></td><td style="text-align:left;"><code>git branch -r</code></td><td style="text-align:left;">リモートブランチを一覧表示</td></tr><tr><td style="text-align:left;"><code>gbrd</code></td><td style="text-align:left;"><code>git branch -d -r</code></td><td style="text-align:left;">リモート追跡ブランチを削除</td></tr><tr><td style="text-align:left;"><code>gbrsb</code></td><td style="text-align:left;"><code>git show-branch</code></td><td style="text-align:left;">ブランチとそのコミットを表示</td></tr><tr><td style="text-align:left;"><code>gswb</code></td><td style="text-align:left;"><code>git switch</code></td><td style="text-align:left;">ブランチを切り替え（モダン）</td></tr><tr><td style="text-align:left;"><code>gcode</code></td><td style="text-align:left;"><code>git checkout main &amp;&amp; git branch --merged | xargs git branch --delete</code></td><td style="text-align:left;">mainにマージされたブランチを削除</td></tr><tr><td style="text-align:left;"><code>gcom</code></td><td style="text-align:left;"><code>git checkout main &amp;&amp; git fetch origin --prune &amp;&amp; git reset --hard origin/main</code></td><td style="text-align:left;">ローカルmainをリモートに合わせてリセット</td></tr></tbody></table><h3 id="リモートとpush-pull" tabindex="-1">リモートとPush/Pull <a class="header-anchor" href="#リモートとpush-pull" aria-label="Permalink to &quot;リモートとPush/Pull&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gf</code></td><td style="text-align:left;"><code>git fetch</code></td><td style="text-align:left;">リモートからフェッチ</td></tr><tr><td style="text-align:left;"><code>gp</code></td><td style="text-align:left;"><code>git pull</code></td><td style="text-align:left;">リモートからプル</td></tr><tr><td style="text-align:left;"><code>gph</code></td><td style="text-align:left;"><code>git push</code></td><td style="text-align:left;">リモートにプッシュ</td></tr><tr><td style="text-align:left;"><code>gpo</code></td><td style="text-align:left;"><code>git push origin</code></td><td style="text-align:left;">originにプッシュ</td></tr><tr><td style="text-align:left;"><code>gpb</code></td><td style="text-align:left;"><code>git push --set-upstream origin $(git branch --show-current)</code></td><td style="text-align:left;">アップストリームを設定してプッシュ</td></tr><tr><td style="text-align:left;"><code>gpoll</code></td><td style="text-align:left;"><code>git push origin --all</code></td><td style="text-align:left;">すべてのブランチをoriginにプッシュ</td></tr><tr><td style="text-align:left;"><code>gpull</code></td><td style="text-align:left;"><code>git pull</code></td><td style="text-align:left;">リモートからプル</td></tr><tr><td style="text-align:left;"><code>gpush</code></td><td style="text-align:left;"><code>git push</code></td><td style="text-align:left;">リモートにプッシュ</td></tr><tr><td style="text-align:left;"><code>gr</code></td><td style="text-align:left;"><code>git remote</code></td><td style="text-align:left;">リモートを管理</td></tr><tr><td style="text-align:left;"><code>gra</code></td><td style="text-align:left;"><code>git remote add</code></td><td style="text-align:left;">新しいリモートを追加</td></tr><tr><td style="text-align:left;"><code>grall</code></td><td style="text-align:left;"><code>git remote | xargs -L1 git push --all</code></td><td style="text-align:left;">すべてのブランチをすべてのリモートにプッシュ</td></tr><tr><td style="text-align:left;"><code>grao</code></td><td style="text-align:left;"><code>git remote add origin</code></td><td style="text-align:left;">originリモートを追加</td></tr><tr><td style="text-align:left;"><code>grv</code></td><td style="text-align:left;"><code>git remote -v</code></td><td style="text-align:left;">リモートURLを表示</td></tr></tbody></table><h3 id="リバートとリセット" tabindex="-1">リバートとリセット <a class="header-anchor" href="#リバートとリセット" aria-label="Permalink to &quot;リバートとリセット&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>grev</code></td><td style="text-align:left;"><code>git revert</code></td><td style="text-align:left;">コミットを取り消し</td></tr><tr><td style="text-align:left;"><code>grevnc</code></td><td style="text-align:left;"><code>git revert --no-commit</code></td><td style="text-align:left;">自動コミットなしで取り消し</td></tr><tr><td style="text-align:left;"><code>grb</code></td><td style="text-align:left;"><code>git rebase</code></td><td style="text-align:left;">現在のブランチをリベース</td></tr><tr><td style="text-align:left;"><code>grbk</code></td><td style="text-align:left;"><code>git reset --soft HEAD^</code></td><td style="text-align:left;">最後のコミットを取り消し</td></tr><tr><td style="text-align:left;"><code>grescl</code></td><td style="text-align:left;"><code>git reset --hard HEAD~1 &amp;&amp; git clean -fd</code></td><td style="text-align:left;">ハードリセットとクリーン</td></tr><tr><td style="text-align:left;"><code>gresh</code></td><td style="text-align:left;"><code>git reset --hard HEAD~1</code></td><td style="text-align:left;">前のコミットにハードリセット</td></tr><tr><td style="text-align:left;"><code>gresp</code></td><td style="text-align:left;"><code>git reset --hard &amp;&amp; git clean -ffdx</code></td><td style="text-align:left;">初期状態にリセット</td></tr><tr><td style="text-align:left;"><code>gress</code></td><td style="text-align:left;"><code>git reset --soft HEAD~1</code></td><td style="text-align:left;">ソフトリセット</td></tr></tbody></table><h3 id="サブモジュール" tabindex="-1">サブモジュール <a class="header-anchor" href="#サブモジュール" aria-label="Permalink to &quot;サブモジュール&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gsm</code></td><td style="text-align:left;"><code>git submodule</code></td><td style="text-align:left;">サブモジュールを管理</td></tr><tr><td style="text-align:left;"><code>gsmi</code></td><td style="text-align:left;"><code>git submodule init</code></td><td style="text-align:left;">サブモジュールを初期化</td></tr><tr><td style="text-align:left;"><code>gsma</code></td><td style="text-align:left;"><code>git submodule add</code></td><td style="text-align:left;">サブモジュールを追加</td></tr><tr><td style="text-align:left;"><code>gsms</code></td><td style="text-align:left;"><code>git submodule sync</code></td><td style="text-align:left;">サブモジュールURLを同期</td></tr><tr><td style="text-align:left;"><code>gsmu</code></td><td style="text-align:left;"><code>git submodule update</code></td><td style="text-align:left;">サブモジュールを更新</td></tr><tr><td style="text-align:left;"><code>gsmui</code></td><td style="text-align:left;"><code>git submodule update --init</code></td><td style="text-align:left;">更新して初期化</td></tr><tr><td style="text-align:left;"><code>gsmuir</code></td><td style="text-align:left;"><code>git submodule update --init --recursive</code></td><td style="text-align:left;">更新、初期化、再帰</td></tr></tbody></table><h3 id="ツール" tabindex="-1">ツール <a class="header-anchor" href="#ツール" aria-label="Permalink to &quot;ツール&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gg</code></td><td style="text-align:left;"><code>git grep</code></td><td style="text-align:left;">リポジトリコンテンツを検索</td></tr><tr><td style="text-align:left;"><code>gbs</code></td><td style="text-align:left;"><code>git bisect</code></td><td style="text-align:left;">バグを導入したコミットを二分探索</td></tr><tr><td style="text-align:left;"><code>undopush</code></td><td style="text-align:left;"><code>git push -f origin HEAD^:master</code></td><td style="text-align:left;">最後のプッシュを強制取り消し</td></tr></tbody></table><h3 id="署名とセキュリティ" tabindex="-1">署名とセキュリティ <a class="header-anchor" href="#署名とセキュリティ" aria-label="Permalink to &quot;署名とセキュリティ&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>enable-signing</code></td><td style="text-align:left;"><em>(インタラクティブウィザード)</em></td><td style="text-align:left;">GPGまたはSSHコミット署名を設定</td></tr><tr><td style="text-align:left;"><code>verify-signatures</code></td><td style="text-align:left;"><code>git log --show-signature -n 10</code></td><td style="text-align:left;">最後の10コミットの署名を検証</td></tr><tr><td style="text-align:left;"><code>check-signing</code></td><td style="text-align:left;"><code>git config --list | grep &quot;gpg|signing&quot;</code></td><td style="text-align:left;">現在の署名設定を確認</td></tr></tbody></table>',26)])])}const y=e(i,[["render",o]]);export{x as __pageData,y as default};
